mapper.select:
SELECT plan_num, plan_qty, plan_status, plan_start, plan_end, emp_num, item_num, item_name, ename, facility_num, facility_name, currentqty, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT pp.plan_num, pp.plan_qty, pp.plan_status, pp.plan_start, pp.plan_end, pp.emp_num, pp.item_num, i.name AS item_name, e.ename, f.facility_num, f.facility_name, NVL(wo.currentqty, 0) AS currentqty, COUNT(*) OVER() AS total_count FROM production_plan pp LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN emp e ON pp.emp_num = e.emp_num LEFT JOIN facility f ON i.facility_num = f.facility_num LEFT JOIN ( SELECT plan_num, SUM(current_qty) AS currentqty FROM work_order GROUP BY plan_num ) wo ON pp.plan_num = wo.plan_num
AND pp.plan_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND pp.plan_end <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND f.facility_num = #{facility_num}
AND pp.item_num = #{item_num}
AND TO_CHAR(pp.plan_num) LIKE '%' || #{keyword} || '%'
ORDER BY pp.plan_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}
